let searchIndex=[];self.onmessage=async function(e){const{type:t,payload:n}=e.data;if(t==="init")try{const e=await fetch("http://localhost:1313/index.json");searchIndex=await e.json(),self.postMessage({type:"ready"})}catch(e){console.error("Failed to load search index:",e)}else if(t==="search"){const e=n.toLowerCase();if(!e){self.postMessage({type:"results",payload:[]});return}let t=searchIndex.filter(t=>{const n=t.title.toLowerCase(),s=t.summary?t.summary.toLowerCase():"",o=t.tags?t.tags.join(" ").toLowerCase():"";return n.includes(e)||s.includes(e)||o.includes(e)}).slice(0,10);t.length===0&&e.length>2&&(t=fuzzySearch(e,searchIndex).slice(0,5)),self.postMessage({type:"results",payload:t})}};function getLevenshteinDistance(e,t){if(e.length===0)return t.length;if(t.length===0)return e.length;const n=[];for(let e=0;e<=t.length;e++)n[e]=[e];for(let t=0;t<=e.length;t++)n[0][t]=t;for(let s=1;s<=t.length;s++)for(let o=1;o<=e.length;o++)t.charAt(s-1)==e.charAt(o-1)?n[s][o]=n[s-1][o-1]:n[s][o]=Math.min(n[s-1][o-1]+1,Math.min(n[s][o-1]+1,n[s-1][o]+1));return n[t.length][e.length]}function fuzzySearch(e,t){const n=e.split(/\s+/);return t.filter(e=>{const t=e.title.toLowerCase().split(/\s+/),s=e.tags?e.tags.map(e=>e.toLowerCase()):[],o=[...t,...s];return n.some(e=>!(e.length<3)&&o.some(t=>{if(Math.abs(t.length-e.length)>2)return!1;const n=getLevenshteinDistance(e,t);return n<=(e.length>5?2:1)}))})}